document.addEventListener("DOMContentLoaded",()=>{"use strict";const e=document.querySelectorAll(".service-card"),t=t=>{const s=t.classList.contains("is-expanded");e.forEach(e=>{e!==t&&(e.classList.remove("is-expanded"),e.setAttribute("aria-expanded","false"))}),s?(t.classList.remove("is-expanded"),t.setAttribute("aria-expanded","false")):(t.classList.add("is-expanded"),t.setAttribute("aria-expanded","true"))};e.forEach(e=>{e.addEventListener("click",()=>t(e)),e.addEventListener("keydown",s=>{"Enter"!==s.key&&" "!==s.key||(s.preventDefault(),t(e))})})});